</code></pre> <pre><code>class Rectangle:
    def __init__(self, width, height):
        self.width = width
        self.height = height

    @property
    def area(self):
        """Computed on access."""
        return self.width * self.height

    @property
    def perimeter(self):
        return 2 * (self.width + self.height)
